INSERT INTO public.kpis (id, kpi_number, kpi_name, target, unit, category) VALUES (43, '24.', 'ร้อยละของเขตสุขภาพที่มีการบริหารจัดการกำลังคนเพื่อรองรับระบบบริการที่มีประสิทธิภาพ 1) สัดส่วนการกระจายแพทย์ในโรงพยาบาลชุมชนสังกัดสำนักงานปลัดกระทรวงสาธารณสุข', '80', 'ร้อยละ', 'ประเด็นที่ 3 : บุคลากรเป็นเลิศ (People Excellence)');
INSERT INTO public.kpis (id, kpi_number, kpi_name, target, unit, category) VALUES (44, '26.', 'ร้อยละของโรงพยาบาลในเขตสุขภาพผ่านเกณฑ์พัฒนา โรงพยาบาลที่มีการตรวจทางห้องปฏิบัติการอย่างสมเหตุผล (RLU hospital Plus) ตามที่กำหนด', '50', 'ร้อยละ', 'ประเด็นที่ 4 : บริหารเป็นเลิศด้วยธรรมาภิบาล (Governance Excellence)');
INSERT INTO public.kpis (id, kpi_number, kpi_name, target, unit, category) VALUES (45, '27.', 'ร้อยละของหน่วยบริการที่ผ่านเกณฑ์การประเมินประสิทธิภาพ Total Performance Score (TPS)', '55', 'ร้อยละ', 'ประเด็นที่ 4 : บริหารเป็นเลิศด้วยธรรมาภิบาล (Governance Excellence)');
INSERT INTO public.kpis (id, kpi_number, kpi_name, target, unit, category) VALUES (46, '28.', 'อัตราการเพิ่มขึ้นของจำนวนสถานประกอบการด้านการท่องเที่ยวเชิงสุขภาพที่ได้รับมาตรฐานตามที่กำหนด', '1', 'แห่ง', 'ประเด็นที่ 4 : บริหารเป็นเลิศด้วยธรรมาภิบาล (Governance Excellence)');
INSERT INTO public.kpis (id, kpi_number, kpi_name, target, unit, category) VALUES (47, '29.', 'ร้อยละผลิตภัณฑ์สุขภาพชุมชนได้รับการอนุญาต *เพิ่มขึ้นร้อยละ 10 จากปี พ.ศ. 2568', '100', 'ร้อยละ', 'ประเด็นที่ 4 : บริหารเป็นเลิศด้วยธรรมาภิบาล (Governance Excellence)');
INSERT INTO public.kpis (id, kpi_number, kpi_name, target, unit, category) VALUES (48, '30.', 'มูลค่าการใช้ยาสมุนไพรในสิทธิ UC', '125', 'ล้านบาท', 'ประเด็นที่ 4 : บริหารเป็นเลิศด้วยธรรมาภิบาล (Governance Excellence)');
